        if v == math.floor(v) and math.abs(v) < 1e15 then
            return string.format('%d', v)
        end
        return string.format('%g', v)
    elseif t == 'string' then
        local s = v:gsub('\\', '\\\\')
                   :gsub('"', '\\"')
                   :gsub('\n', '\\n')
                   :gsub('\r', '\\r')
                   :gsub('\t', '\\t')
