        if c == '}' then return obj, i + 1 end
        if c ~= ',' then error('expected , or } in object') end
        i = i + 1
    end
end
json_parse_value = function(s, i)
    i = json_skip_ws(s, i)
    local c = s:sub(i, i)
    if c == '"' then
        return json_parse_string(s, i)
    elseif c == '[' then
        return json_parse_array(s, i)
    elseif c == '{' then
        return json_parse_object(s, i)
    elseif s:sub(i, i+3) == 'true' then
        return true, i + 4
    elseif s:sub(i, i+4) == 'false' then
        return false, i + 5
    elseif s:sub(i, i+3) == 'null' then
        return nil, i + 4
    else
        local num_s, j = s:match('^(-?%d+%.?%d*[eE]?[+-]?%d*)()', i)
        if num_s then
            return tonumber(num_s), j
        end
        error('unexpected token at pos ' .. i .. ': ' .. s:sub(i, i+8))
    end
end
local function json_decode(s)
    if not s or s == '' then return nil end
    local ok, v = pcall(function()
        local val, _ = json_parse_value(s, 1)
        return val
    end)
    if ok then return v end
    onion.log('oRPG json_decode error: ' .. tostring(v))
    return nil
end
proto.json_encode = json_encode
proto.json_decode = json_decode
local function uint16_be_bytes(n)
    return string.char(math.floor(n / 256) % 256, n % 256)
end
function proto.encode(msg_type, msg_id, body)
    local json = json_encode(body)
    local bytes = json  -- Lua strings are byte arrays
    local total_chunks = math.max(1, math.ceil(#bytes / proto.BODY_MAX))
    if total_chunks > 255 then
        error('message too large: ' .. #bytes .. ' bytes')
    end
    local frames = {}
    for seq = 0, total_chunks - 1 do
        local start  = seq * proto.BODY_MAX + 1
        local finish = math.min(start + proto.BODY_MAX - 1, #bytes)
        local chunk  = bytes:sub(start, finish)
        local more   = (seq < total_chunks - 1) and proto.FLAG_MORE or 0x00
        local header = string.char(
            proto.MAGIC,
            proto.VERSION,
            msg_type,
            more
        ) .. uint16_be_bytes(msg_id) .. string.char(seq, total_chunks)
        frames[#frames + 1] = header .. chunk
    end
    return frames
end
function proto.decode_frame(raw)
    if #raw < proto.HEADER then
        return nil, 'frame too short'
    end
    local b = {raw:byte(1, proto.HEADER)}
    if b[1] ~= proto.MAGIC then
        return nil, string.format('bad magic 0x%02x', b[1])
    end
    if b[2] ~= proto.VERSION then
        return nil, string.format('unsupported version 0x%02x', b[2])
    end
    local frame = {
        msg_type = b[3],
        flags    = b[4],
        msg_id   = b[5] * 256 + b[6],
        seq      = b[7],
        total    = b[8],
        more     = (b[4] % 2 == 1),
        body_raw = raw:sub(proto.HEADER + 1),
    }
    return frame
end
function proto.new_reassembler()
    local r = {
        chunks    = {},
        total     = 0,
        msg_type  = nil,
        msg_id    = nil,
    }
    function r:push(frame)
        self.msg_type = frame.msg_type
        self.msg_id   = frame.msg_id
        self.total    = frame.total
        self.chunks[frame.seq] = frame.body_raw
        local have = 0
        for _ in pairs(self.chunks) do have = have + 1 end
        if have < self.total then return nil end
        local parts = {}
        for i = 0, self.total - 1 do
            if not self.chunks[i] then return nil end  -- gap; wait
            parts[#parts + 1] = self.chunks[i]
        end
        local full = table.concat(parts)
        return json_decode(full)
    end
    function r:reset()
        self.chunks   = {}
        self.total    = 0
        self.msg_type = nil
        self.msg_id   = nil
    end
    return r
end
return proto
end

package.preload["lib.router"] = function(...)
local ui = require('lib.ui')
local router = {}
local _stack = {}
local _loaded = {}
local function load_screen(challenge_id)
    if _loaded[challenge_id] then
        return _loaded[challenge_id]
    end
    local slug = challenge_id:gsub('%.', '_')
    local mod_name = 'screens.' .. slug
    local ok, mod = pcall(require, mod_name)
    if not ok then
        onion.log('router: failed to load screen ' .. mod_name .. ': ' .. tostring(mod))
        return nil, tostring(mod)
    end
    if type(mod) ~= 'table' then
        return nil, 'screen module ' .. mod_name .. ' did not return a table'
    end
    if type(mod.begin)  ~= 'function' then return nil, mod_name .. ' missing begin()' end
    if type(mod.update) ~= 'function' then return nil, mod_name .. ' missing update()' end
    if type(mod.render) ~= 'function' then return nil, mod_name .. ' missing render()' end
    _loaded[challenge_id] = mod
    return mod
end
function router.push(challenge_id, ctx)
    local mod, err = load_screen(challenge_id)
    if not mod then
        return nil, err
    end
    local ok, begin_err = pcall(mod.begin, ctx)
    if not ok then
        return nil, 'screen begin error: ' .. tostring(begin_err)
    end
    _stack[#_stack + 1] = { id = challenge_id, mod = mod, ctx = ctx }
    onion.log('router: entered screen ' .. challenge_id)
    return true
end
function router.pop()
    if #_stack > 0 then
        local top = _stack[#_stack]
        _stack[#_stack] = nil
        onion.log('router: exited screen ' .. top.id)
    end
end
function router.current_id()
    if #_stack == 0 then return nil end
    return _stack[#_stack].id
end
function router.update(ctx, dt)
    if #_stack == 0 then return nil end
    local top = _stack[#_stack]
    local ok, result = pcall(top.mod.update, ctx, dt)
    if not ok then
        onion.log('router: update error in ' .. top.id .. ': ' .. tostring(result))
        return 'error'
    end
    return result
end
function router.render(ctx)
    if #_stack == 0 then return end
    local top = _stack[#_stack]
    onion.clear_display()
    local ok, err = pcall(top.mod.render, ctx)
    if not ok then
        onion.log('router: render error in ' .. top.id .. ': ' .. tostring(err))
        onion.display_lines({ 'RENDER ERROR', top.id, tostring(err):sub(1, 30) },
            6, 40, 18, { font = 'small', clear = false })
    end
end
function router.replace(challenge_id, ctx)
    router.pop()
    return router.push(challenge_id, ctx)
end
return router
end

