        end
    elseif state.phase == 'defeat' then
        if pressed == 'select' or pressed == 'cancel' then
            return 'done'
        end
    elseif state.phase == 'done' then
        if pressed == 'select' or pressed == 'cancel' then
            return 'done'
        end
    end
