        ui.title('SERVER ROOM CLEARED', 4)
        ui.divider(18)
        onion.display_text('KILL LOGGED (server-verified)', 6, 24,
            { font = 'small', clear = false })
        ui.divider(34)
        local lines = ui.wrap_text(
